import { createStore } from 'vuex'
import { authService } from '@/services/authService'
import { STORAGE_KEYS } from '@/utils/storage'
import { basicProfile } from '@/api/profile'

export default createStore({
  state: {
    isAuthenticated: false,
    userInfo: null,
    basicInfo: null,
    completeness: null
  },

  mutations: {
    SET_AUTH(state, isAuthenticated) {
      state.isAuthenticated = isAuthenticated
    },

    SET_USER_INFO(state, userInfo) {
      state.userInfo = userInfo
    },

    SET_BASIC_INFO(state, basicInfo) {
      state.basicInfo = basicInfo
    },

    SET_COMPLETENESS(state, completeness) {
      state.completeness = completeness
    }
  },

  getters: {
    userAvatar: state => {
      return state.basicInfo?.avatar || '/default-avatar.png'
    },

    userName: state => {
      return state.basicInfo?.name || state.userInfo?.username || '未设置昵称'
    },

    userPhone: state => {
      return state.basicInfo?.phone || state.userInfo?.phone
    },

    profileCompleteness: state => {
      return state.completeness || 0
    }
  },

  actions: {
    async checkAuth({ commit, dispatch }) {
      const isAuthenticated = authService.isAuthenticated()
      commit('SET_AUTH', isAuthenticated)
      if (isAuthenticated) {
        await dispatch('fetchUserInfo')
      }
      return isAuthenticated
    },

    async fetchUserInfo({ commit }) {
      try {
        const response = await basicProfile.getBasicInfo()
        if (response.data?.code === 200) {
          const { user, basic_info } = response.data.data
          if (user) {
            commit('SET_USER_INFO', user)
          }
          if (basic_info) {
            commit('SET_BASIC_INFO', basic_info)
          }
          return response.data.data
        }
      } catch (error) {
        console.error('Failed to get user info:', error)
        if (error.response?.status === 401) {
          commit('SET_AUTH', false)
          commit('SET_USER_INFO', null)
          commit('SET_BASIC_INFO', null)
        }
        throw error
      }
    },

    async updateBasicInfo({ commit }, { type, data }) {
      try {
        let response
        if (type === 'avatar') {
          response = await basicProfile.uploadAvatar(data)
        } else if (type === 'basic') {
          response = await basicProfile.updateBasicInfo(data)
        }

        if (response.data?.code === 200) {
          if (type === 'avatar') {
            commit('SET_AVATAR_UPDATE_TIME', Date.now())
          }
          const { user, basic_info } = response.data.data
          if (user) {
            commit('SET_USER_INFO', user)
          }
          if (basic_info) {
            commit('SET_BASIC_INFO', basic_info)
          }
        }
        return response
      } catch (error) {
        console.error('Failed to update basic info:', error)
        throw error
      }
    },

    async logout({ commit }) {
      try {
        await authService.logout()
      } catch (error) {
        console.error('Logout failed:', error)
      } finally {
        commit('SET_AUTH', false)
        commit('SET_USER_INFO', null)
        commit('SET_BASIC_INFO', null)
      }
    },

    async fetchCompleteness({ commit }) {
      try {
        const response = await basicProfile.getCompleteness()
        if (response.data?.code === 200) {
          commit('SET_COMPLETENESS', response.data.data)
        }
      } catch (error) {
        console.error('Failed to get completeness:', error)
      }
    }
  }
})
